using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// from DI automatically. They never appear in the tool schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all items from the API. Returns JSON array.")]
    public async Task<string> ListItems(
        [Description("Maximum number of items to return (1-100)")] int limit = 20,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing up to {Limit} items", limit);
        var response = await httpClient.GetStringAsync($"/items?limit={limit}", cancellationToken);
        return response;
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique identifier of the item")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching item {Id}", id);
        var response = await httpClient.GetAsync($"/items/{id}", cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            return $"Error: {response.StatusCode}";
        }

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }

    [McpServerTool, Description("Create a new item with the given name and optional description.")]
    public async Task<string> CreateItem(
        [Description("Name for the new item")] string name,
        [Description("Optional description of the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item {Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/items", content, cancellationToken);
        var body = await response.Content.ReadAsStringAsync(cancellationToken);

        return response.IsSuccessStatusCode
            ? body
            : $"Error ({response.StatusCode}): {body}";
    }

    [McpServerTool(ReadOnly = true), Description("Search items by keyword.")]
    public async Task<string> SearchItems(
        [Description("Search query string")] string query,
        [Description("Maximum results to return (1-50)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching for '{Query}' (limit {Limit})", query, limit);
        var encoded = Uri.EscapeDataString(query);
        var response = await httpClient.GetStringAsync(
            $"/items/search?q={encoded}&limit={limit}", cancellationToken);
        return response;
    }
}

